commands.effect_on_receipt:
pseudocode:
1. if rate_limiter.too_many_unique_requests(last_10_min) then
    send_command_response_status(FAILURE);
    return;
2. account_req := lookup_account_by_temp_id(TempAccountIdentifier);
3. account_active := get_active_account_for_content_app();
4. if account_req = account_active and temp_id_not_expired(TempAccountIdentifier, 10_min) then
    setup_pin := get_commissionee_setup_pin(account_req);
    send_GetSetupPINResponse(SetupPIN := setup_pin);
   else
    send_GetSetupPINResponse(SetupPIN := "");
5. ensure_temp_identifier_lifetime(TempAccountIdentifier, max_age := 10_min);

pseudocode (client side):
1. if SetupPIN = "" then
     account_match := false;
     abort_pase_commissioning();
   else
     account_match := true;
     proceed_with_pase_commissioning(SetupPIN);

pseudocode:
1. if rate_limiter.too_many_unique_requests(last_10_min) then
    send_command_response_status(FAILURE);
    return;
2. if temp_id_expired(TempAccountIdentifier, 10_min) then
    send_command_response_status(FAILURE);
    return;
3. acct := lookup_account_by_temp_id(TempAccountIdentifier);
4. if acct = null then
    send_command_response_status(FAILURE);
    return;
5. if not has_current_active_setup_pin(acct, SetupPIN) then
    send_command_response_status(FAILURE);
    return;
6. if policy_allow_auto_login(acct) then
     set_active_account_for_content_app(acct);
     if Node is present then
        grant_content_app_access_to_node(acct, Node);
7. send_success_response();
8. mapping_service_enforce_aggressive_timeout(TempAccountIdentifier, SetupPIN);

pseudocode:
1. current_acct := get_active_account_for_content_app();
2. if current_acct = null then
     send_success_response();
     return;
3. clear_active_account_for_content_app();
4. if Node is present then
     record_node_logout(Node);
     emit_LoggedOut_event(Node := Node);
   else
     record_global_logout();
     emit_LoggedOut_event(Node := null);
5. send_success_response();
